extension HybridWebViewController: WKScriptMessageHandler {
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any] else { return }
        
        switch message.name {
        case "camera":
            handleCameraRequest(body)
        case "pushNotifications":
            handlePushNotificationRequest(body)
        case "inAppPurchase":
            handleInAppPurchaseRequest(body)
        case "native":
            handleNativeRequest(body)
        default:
            break
        }
    }
    
    private func handleCameraRequest(_ params: [String: Any]) {
        guard let action = params["action"] as? String else { return }
        
        switch action {
        case "requestPermission":
            requestCameraPermission { granted in
                self.sendMessageToWeb(event: "cameraPermission", data: ["granted": granted])
            }
        case "openCamera":
            openCamera(params)
        case "openPhotoLibrary":
            openPhotoLibrary(params)
        default:
            break
        }
    }
    
    private func requestCameraPermission(completion: @escaping (Bool) -> Void) {
        AVCaptureDevice.requestAccess(for: .video) { granted in
            DispatchQueue.main.async {
                completion(granted)
            }
        }
    }
    
    private func openCamera(_ params: [String: Any]) {
        guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
            sendMessageToWeb(event: "cameraError", data: ["error": "Camera not available"])
            return
        }
        
        AVCaptureDevice.requestAccess(for: .video) { granted in
            DispatchQueue.main.async {
                if granted {
                    let picker = UIImagePickerController()
                    picker.sourceType = .camera
                    picker.delegate = self
                    picker.allowsEditing = params["allowEditing"] as? Bool ?? false
                    self.present(picker, animated: true)
                } else {
                    self.sendMessageToWeb(event: "cameraError", data: ["error": "Camera permission denied"])
                }
            }
        }
    }
    
    private func openPhotoLibrary(_ params: [String: Any]) {
        let picker = UIImagePickerController()
        picker.sourceType = .photoLibrary
        picker.delegate = self
        picker.allowsEditing = params["allowEditing"] as? Bool ?? false
        present(picker, animated: true)
    }
    
    private func handlePushNotificationRequest(_ params: [String: Any]) {
        guard let action = params["action"] as? String else { return }
        
        switch action {
        case "requestPermission":
            requestPushNotificationPermission()
        case "getToken":
            getPushNotificationToken()
        case "checkPermission":
            checkPushNotificationPermission()
        default:
            break
        }
    }
    
    private func requestPushNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { granted, error in
            DispatchQueue.main.async {
                if granted {
                    UIApplication.shared.registerForRemoteNotifications()
                }
                self.sendMessageToWeb(event: "pushPermission", data: ["granted": granted, "error": error?.localizedDescription ?? ""])
            }
        }
    }
    
    private func getPushNotificationToken() {
        if let token = UserDefaults.standard.string(forKey: "deviceToken") {
            sendMessageToWeb(event: "pushToken", data: ["token": token])
        } else {
            sendMessageToWeb(event: "pushToken", data: ["token": ""])
        }
    }
    
    private func checkPushNotificationPermission() {
        UNUserNotificationCenter.current().getNotificationSettings { settings in
            DispatchQueue.main.async {
                let granted = settings.authorizationStatus == .authorized
                self.sendMessageToWeb(event: "pushPermissionStatus", data: ["granted": granted])
            }
        }
    }
    
    private func handleInAppPurchaseRequest(_ params: [String: Any]) {
        guard let action = params["action"] as? String else { return }
        
        switch action {
        case "purchase":
            if let productId = params["productId"] as? String {
                purchaseProduct(productId: productId)
            }
        case "restore":
            restorePurchases()
        case "getProducts":
            if let productIds = params["productIds"] as? [String] {
                fetchProducts(productIds: productIds)
            }
        default:
            break
        }
    }
    
    private func purchaseProduct(productId: String) {
        let request = SKProductsRequest(productIdentifiers: [productId])
        request.delegate = self
        request.start()
    }
    
    private func restorePurchases() {
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    private func fetchProducts(productIds: [String]) {
        let request = SKProductsRequest(productIdentifiers: Set(productIds))
        request.delegate = self
        request.start()
    }
    
    private func handleNativeRequest(_ params: [String: Any]) {
        guard let action = params["action"] as? String else { return }
        
        switch action {
        case "share":
            if let text = params["text"] as? String {
                shareContent(text: text, url: params["url"] as? String)
            }
        case "vibrate":
            vibrateDevice()
        case "getDeviceInfo":
            sendDeviceInfo()
        case "openURL":
            if let urlString = params["url"] as? String {
                openExternalURL(urlString)
            }
        case "setStatusBar":
            if let style = params["style"] as? String {
                setStatusBarStyle(style)
            }
        default:
            break
        }
    }
    
    private func shareContent(text: String, url: String?) {
        var items: [Any] = [text]
        if let urlString = url, let shareURL = URL(string: urlString) {
            items.append(shareURL)
        }
        
        let activityVC = UIActivityViewController(activityItems: items, applicationActivities: nil)
        
        if let popover = activityVC.popoverPresentationController {
            popover.sourceView = view
            popover.sourceRect = CGRect(x: view.bounds.midX, y: view.bounds.midY, width: 0, height: 0)
            popover.permittedArrowDirections = []
        }
        
        present(activityVC, animated: true)
    }
    
    private func vibrateDevice() {
        let generator = UIImpactFeedbackGenerator(style: .medium)
        generator.impactOccurred()
    }
    
    private func sendDeviceInfo() {
        let device = UIDevice.current
        let deviceInfo: [String: Any] = [
            "model": device.model,
            "systemName": device.systemName,
            "systemVersion": device.systemVersion,
            "name": device.name,
            "identifierForVendor": device.identifierForVendor?.uuidString ?? "",
            "screenWidth": UIScreen.main.bounds.width,
            "screenHeight": UIScreen.main.bounds.height,
            "scale": UIScreen.main.scale
        ]
        sendMessageToWeb(event: "deviceInfo", data: deviceInfo)
    }
    
    private func openExternalURL(_ urlString: String) {
        guard let url = URL(string: urlString) else { return }
        if UIApplication.shared.canOpenURL(url) {
            UIApplication.shared.open(url)
        }
    }
    
    private func setStatusBarStyle(_ style: String) {
        var statusBarStyle: UIStatusBarStyle = .default
        if style == "light" {
            statusBarStyle = .lightContent
        } else if style == "dark" {
            if #available(iOS 13.0, *) {
                statusBarStyle = .darkContent
            }
        }
    }
    
    private func sendMessageToWeb(event: String, data: [String: Any]) {
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: data, options: [])
            if let jsonString = String(data: jsonData, encoding: .utf8) {
                let script = "window.dispatchEvent(new CustomEvent('\(event)', { detail: \(jsonString) }));"
                webView.evaluateJavaScript(script)
            }
        } catch {
            print("Error serializing data: \(error)")
        }
    }
}

extension HybridWebViewController: WKNavigationDelegate {
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        progressView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        progressView.isHidden = true
        showError(message: "Failed to load page: \(error.localizedDescription)")
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        if let url = navigationAction.request.url {
            if url.scheme == "tel" || url.scheme == "mailto" || url.scheme == "sms" {
                if UIApplication.shared.canOpenURL(url) {
                    UIApplication.shared.open(url)
                    decisionHandler(.cancel)
                    return
                }
            }
        }
        decisionHandler(.allow)
    }
    
    private func showError(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

